    "title": "Problem 2906",
    "description": "Write a Python function called `iterate_index_pairs` that must use iter() and next() to visit every value and pair every item with its zero-based index. Use iterator syntax.\nDifficulty: Difficult.\nExamples:\n  iterate_index_pairs([[1, 2, 3], [-2, 0, 5], [3, 3, 1]]) -> [[[0, 1], [1, 2], [2, 3]], [[0, -2], [1, 0], [2, 5]], [[0, 3], [1, 3], [2, 1]]]\n  iterate_index_pairs([[3, 3, 1], [1, 2, 3]]) -> [[[0, 3], [1, 3], [2, 1]], [[0, 1], [1, 2], [2, 3]]]",
    "initialCode": "def iterate_index_pairs(values):\n    pass",
    "solution": "# Using function approach\n# Example 1: canonical iterator solution\ndef iterate_index_pairs(values):\n    iterator = iter(values)\n    result = []\n    while True:\n        try:\n            item = next(iterator)\n        except StopIteration:\n            break\n        result.append(list(enumerate(item)))\n    return result\n\nprint(iterate_index_pairs([[1, 2, 3], [-2, 0, 5], [3, 3, 1]]))  # Expected: [[[0, 1], [1, 2], [2, 3]], [[0, -2], [1, 0], [2, 5]], [[0, 3], [1, 3], [2, 1]]]\nprint(iterate_index_pairs([[3, 3, 1], [1, 2, 3]]))  # Expected: [[[0, 3], [1, 3], [2, 1]], [[0, 1], [1, 2], [2, 3]]]\n\n# Example 2: nested helper approach\ndef solve_problem_2906(values):\n    def execute():\n        iterator = iter(values)\n        result = []\n        while True:\n            try:\n                item = next(iterator)\n            except StopIteration:\n                break\n            result.append(list(enumerate(item)))\n        return result\n    return execute()\n\nprint(solve_problem_2906([[1, 2, 3], [-2, 0, 5], [3, 3, 1]]))\n\n# Example 3: static method approach\nclass Problem2906Solution:\n    @staticmethod\n    def iterate_index_pairs(values):\n        iterator = iter(values)\n        result = []\n        while True:\n            try:\n                item = next(iterator)\n            except StopIteration:\n                break\n            result.append(list(enumerate(item)))\n        return result\n\nprint(Problem2906Solution.iterate_index_pairs([[3, 3, 1], [1, 2, 3]]))\n\n# Example 4: assigned result approach\nresult = iterate_index_pairs([[1, 2, 3], [-2, 0, 5], [3, 3, 1]])\nprint(result)\n\n# Example 5: direct call\nprint(iterate_index_pairs([[-2, 0, 5]]))",
