    "initialCode": "def pipeline_nonzero_count(value):\n    pass",
    "solution": "# Using function approach\n# Example 1: canonical decorator solution\ndef pipeline_nonzero_count(value):\n    def apply_transform(function):\n        def wrapped(value):\n            original = function(value)\n            return sum(item != 0 for item in original)\n        return wrapped\n\n    @apply_transform\n    def preserve(value):\n        return value\n\n    return preserve(value)\n\nprint(pipeline_nonzero_count([1, 2, 3]))  # Expected: 3\nprint(pipeline_nonzero_count([-2, 0, 5]))  # Expected: 2\n\n# Example 2: nested helper approach\ndef solve_problem_3157(value):\n    def execute():\n        def apply_transform(function):\n            def wrapped(value):\n                original = function(value)\n                return sum(item != 0 for item in original)\n            return wrapped\n    \n        @apply_transform\n        def preserve(value):\n            return value\n    \n        return preserve(value)\n    return execute()\n\nprint(solve_problem_3157([1, 2, 3]))\n\n# Example 3: static method approach\nclass Problem3157Solution:\n    @staticmethod\n    def pipeline_nonzero_count(value):\n        def apply_transform(function):\n            def wrapped(value):\n                original = function(value)\n                return sum(item != 0 for item in original)\n            return wrapped\n    \n        @apply_transform\n        def preserve(value):\n            return value\n    \n        return preserve(value)\n\nprint(Problem3157Solution.pipeline_nonzero_count([-2, 0, 5]))\n\n# Example 4: assigned result approach\nresult = pipeline_nonzero_count([1, 2, 3])\nprint(result)\n\n# Example 5: direct call\nprint(pipeline_nonzero_count([3, 3, 1]))",
