    "initialCode": "def resource_double(value):\n    pass",
    "solution": "# Using function approach\n# Example 1: canonical context manager solution\ndef resource_double(value):\n    class OperationResource:\n        def __init__(self, value):\n            self.value = value\n            self.active = False\n\n        def __enter__(self):\n            self.active = True\n            return self\n\n        def __exit__(self, exc_type, exc_value, traceback):\n            self.active = False\n            return False\n\n    with OperationResource(value) as resource:\n        return resource.value * 2\n\nprint(resource_double(5))  # Expected: 10\nprint(resource_double(-4))  # Expected: -8\n\n# Example 2: nested helper approach\ndef solve_problem_3208(value):\n    def execute():\n        class OperationResource:\n            def __init__(self, value):\n                self.value = value\n                self.active = False\n    \n            def __enter__(self):\n                self.active = True\n                return self\n    \n            def __exit__(self, exc_type, exc_value, traceback):\n                self.active = False\n                return False\n    \n        with OperationResource(value) as resource:\n            return resource.value * 2\n    return execute()\n\nprint(solve_problem_3208(5))\n\n# Example 3: static method approach\nclass Problem3208Solution:\n    @staticmethod\n    def resource_double(value):\n        class OperationResource:\n            def __init__(self, value):\n                self.value = value\n                self.active = False\n    \n            def __enter__(self):\n                self.active = True\n                return self\n    \n            def __exit__(self, exc_type, exc_value, traceback):\n                self.active = False\n                return False\n    \n        with OperationResource(value) as resource:\n            return resource.value * 2\n\nprint(Problem3208Solution.resource_double(-4))\n\n# Example 4: assigned result approach\nresult = resource_double(5)\nprint(result)\n\n# Example 5: direct call\nprint(resource_double(0))",
